class LRUCache:
    def __init__(self, capacity):
        self.cap = capacity; self.cache = {}  # key→node
        self.head = Node(0,0); self.tail = Node(0,0)  # dummies
        self.head.next = self.tail; self.tail.prev = self.head
    def _remove(self, node):
        node.prev.next = node.next; node.next.prev = node.prev
    def _insert_front(self, node):
        node.next = self.head.next; node.prev = self.head
        self.head.next.prev = node; self.head.next = node
    def get(self, key):
        if key not in self.cache: return -1
        self._remove(self.cache[key]); self._insert_front(self.cache[key])
        return self.cache[key].val
    def put(self, key, value):
        if key in self.cache: self._remove(self.cache[key])
        node = Node(key, value); self.cache[key] = node; self._insert_front(node)
        if len(self.cache) > self.cap:
            lru = self.tail.prev; self._remove(lru); del self.cache[lru.key]
