import bisect

def lengthOfLIS(nums):
    tails = []  # tails[i] = smallest ending element of LIS of length i+1

    for num in nums:
        pos = bisect.bisect_left(tails, num)  # find leftmost pos where tails[pos] >= num

        if pos == len(tails):
            tails.append(num)  # extend LIS
        else:
            tails[pos] = num   # replace to maintain smallest possible tail

    return len(tails)

