import numpy as np

# Adam optimizer from scratch
class Adam:
    def __init__(self, lr=0.001, beta1=0.9, beta2=0.999, eps=1e-8):
        self.lr = lr; self.beta1 = beta1; self.beta2 = beta2; self.eps = eps
        self.m = None; self.v = None; self.t = 0

    def update(self, params, grads):
        if self.m is None:
            self.m = np.zeros_like(params)
            self.v = np.zeros_like(params)
        self.t += 1
        self.m = self.beta1 * self.m + (1 - self.beta1) * grads
        self.v = self.beta2 * self.v + (1 - self.beta2) * grads**2
        m_hat = self.m / (1 - self.beta1**self.t)  # bias correction
        v_hat = self.v / (1 - self.beta2**self.t)
        return params - self.lr * m_hat / (np.sqrt(v_hat) + self.eps)

import numpy as np

# Naive Bayes from scratch
class NaiveBayes:
    def fit(self, X, y):
        self.classes = np.unique(y)
        self.priors = {c: np.mean(y == c) for c in self.classes}
        self.means = {c: X[y == c].mean(axis=0) for c in self.classes}
        self.stds = {c: X[y == c].std(axis=0) + 1e-9 for c in self.classes}

    def predict(self, X):
        log_probs = []
        for c in self.classes:
            log_prior = np.log(self.priors[c])
            # Gaussian likelihood (log)
            log_likelihood = -0.5 * np.sum(
                np.log(2*np.pi*self.stds[c]**2) +
                ((X - self.means[c])**2 / self.stds[c]**2), axis=1)
            log_probs.append(log_prior + log_likelihood)
        return self.classes[np.argmax(np.array(log_probs), axis=0)]

import numpy as np

def entropy(probs):
    probs = np.array(probs)
    return -np.sum(probs * np.log(probs + 1e-9))

def cross_entropy(y_true, y_pred):
    return -np.sum(y_true * np.log(y_pred + 1e-9))

def information_gain(parent, left, right):
    n = len(parent)
    nl, nr = len(left), len(right)
    ig = entropy(parent) - (nl/n)*entropy(left) - (nr/n)*entropy(right)
    return ig

# KL divergence
def kl_divergence(p, q):
    return np.sum(p * np.log((p + 1e-9) / (q + 1e-9)))

